INFO FOR DB;
DEFINE TABLE user2 SCHEMAFULL
	PERMISSIONS
		FOR select, update, delete WHERE id = $auth.id;

DEFINE FIELD name ON user2 TYPE string;
DEFINE FIELD email ON user2 TYPE string ASSERT string::is::email($value);
DEFINE FIELD password ON user2 TYPE string;

DEFINE INDEX email ON user2 FIELDS email UNIQUE;

INFO FOR DB;

DEFINE ACCESS user2 ON DATABASE TYPE RECORD
	SIGNIN (
		SELECT * FROM user2 WHERE email = $email AND crypto::argon2::compare(password, $password)
	)
	SIGNUP (
		CREATE user2 CONTENT {
			name: $name,
			email: $email,
			password: crypto::argon2::generate($password)
		}
	);

INFO FOR DB;

SELECT * FROM user2;

